export interface LicenseFeatures {
  maxUsers:     number
  maxAgents:    number
  maxStorageMb: number
  branding:     boolean
  integrations: boolean   // AD / LDAP, Azure AD, Google Workspace (all in one menu)
}

export interface License {
  type:          'DEMO' | 'PRODUCTION'
  licensee:      string
  domain:        string
  issuedAt:      string
  updatesUntil:  string | null
  trialEndsAt?:  string
  features:      LicenseFeatures
  signature:     string
}

export interface LicenseStatus {
  valid:              boolean
  expired:            boolean
  expiresSoon:        boolean
  daysLeft:           number | null
  readOnly:           boolean
  message:            string | null
  // Update subscription (PRODUCTION only)
  updatesExpired:     boolean
  updatesExpiringSoon: boolean
  updatesDaysLeft:    number | null
}

// ── Compute runtime status from a validated license ───────────
export function getLicenseStatus(license: License): LicenseStatus {
  const today = new Date()

  if (license.type === 'DEMO' && license.trialEndsAt) {
    const trialEnd    = new Date(license.trialEndsAt)
    const msLeft      = trialEnd.getTime() - today.getTime()
    const daysLeft    = Math.ceil(msLeft / (1000 * 60 * 60 * 24))
    const expired     = today > trialEnd
    const expiresSoon = !expired && daysLeft <= 7

    return {
      valid:               !expired,
      expired,
      expiresSoon,
      daysLeft:            Math.max(0, daysLeft),
      readOnly:            expired,
      message:             expired
        ? 'Your EduDesk trial has expired. Contact support@ctitans.com to purchase.'
        : expiresSoon
          ? `Your trial expires in ${daysLeft} day${daysLeft === 1 ? '' : 's'}. Contact support@ctitans.com to purchase.`
          : null,
      updatesExpired:      false,
      updatesExpiringSoon: false,
      updatesDaysLeft:     null,
    }
  }

  // ── PRODUCTION — app always runs; check update subscription ──
  let updatesExpired      = false
  let updatesExpiringSoon = false
  let updatesDaysLeft: number | null = null
  let updateMessage: string | null   = null

  if (license.updatesUntil) {
    const updatesEnd = new Date(license.updatesUntil)
    const msLeft     = updatesEnd.getTime() - today.getTime()
    const daysLeft   = Math.ceil(msLeft / (1000 * 60 * 60 * 24))

    updatesExpired      = today > updatesEnd
    updatesExpiringSoon = !updatesExpired && daysLeft <= 30
    updatesDaysLeft     = Math.max(0, daysLeft)

    if (updatesExpired) {
      updateMessage =
        `Update subscription expired on ${license.updatesUntil}. ` +
        `The app continues to run normally — contact support@ctitans.com to renew updates.`
    } else if (updatesExpiringSoon) {
      updateMessage =
        `Update subscription expires in ${daysLeft} day${daysLeft === 1 ? '' : 's'} (${license.updatesUntil}). ` +
        `Contact support@ctitans.com to renew.`
    }
  }

  return {
    valid:               true,
    expired:             false,
    expiresSoon:         false,
    daysLeft:            null,
    readOnly:            false,
    message:             updateMessage,
    updatesExpired,
    updatesExpiringSoon,
    updatesDaysLeft,
  }
}
